### Tool Registration Pattern

\`\`\`typescript
function registerMatchTools(server: McpServer, matchService: MatchService) {
  server.registerTool(
    'abacus_match_gherkin',
    {
      title: 'Match Gherkin Step',
      description: 'Match a Gherkin step text to an Action in the application graph. Returns exact match, fuzzy candidates, or a creation suggestion for new features.',
      inputSchema: z.object({
        stepText: z.string().describe('The Gherkin step text to match (without Given/When/Then keyword)'),
        keyword: z.enum(['Given', 'When', 'Then', 'And']).optional().describe('The Gherkin keyword'),
        autoCreate: z.boolean().optional().describe('Auto-create suggested Action if no match found'),
      }),
    },
    async ({ stepText, keyword, autoCreate }) => {
      const result = matchService.match(stepText, keyword);

      if (autoCreate && result.tier === 'suggest') {
        const created = actionService.create(result.suggestion);
        return {
          content: [{ type: 'text', text: JSON.stringify({ ...result, created }, null, 2) }],
        };
      }

      return {
        content: [{ type: 'text', text: JSON.stringify(result, null, 2) }],
      };
    }
  );
}
\`\`\`

